trait Trait {}
struct T;
impl Trait for T {}

pub fn insert<T>(vector: &mut Vec<Box<dyn Trait>>, value: T) -> &T 
where 
    T: Trait + 'static, // 'static est nécessaire pour downcast
{
    // Insère la valeur dans le vecteur
    vector.push(Box::new(value));

    // Obtient la référence à la valeur insérée
    let it = vector.last().unwrap();

    // Effectue un downcast pour récupérer la référence d'origine
    it.downcast_ref::<T>().unwrap()
